#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0)
        return a;
    return gcd(b, a % b);
}

int main() {
    int N;
    scanf("%d", &N);
    int* arr = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    int maxGroups = 0;
    for (int mask = 0; mask < (1 << N); mask++) {
        int valid = 1;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if ((mask & (1 << i)) && (mask & (1 << j)) && gcd(arr[i], arr[j]) != 1) {
                    valid = 0;
                    break;
                }
            }
            if (!valid)
                break;
        }
        if (valid) {
            int count = 0;
            for (int i = 0; i < N; i++) {
                if (mask & (1 << i))
                    count++;
            }
            maxGroups = (maxGroups > count) ? maxGroups : count;
        }
    }
    printf("%d\n", maxGroups);
    return 0;
}

