// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    public static int gcd(int a, int b) {
        if (b == 0)
            return a;
        return gcd(b, a % b);
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] arr = new int[N];
        for (int i = 0; i < N; i++) {
            arr[i] = sc.nextInt();
        }
        int maxGroups = 0;
        for (int mask = 0; mask < (1 << N); mask++) {
            int valid = 1;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if ((mask & (1 << i)) != 0 && (mask & (1 << j)) != 0 && gcd(arr[i], arr[j]) != 1) {
                        valid = 0;
                        break;
                    }
                }
                if (valid == 0)
                    break;
            }
            if (valid != 0) {
                int count = 0;
                for (int i = 0; i < N; i++) {
                    if ((mask & (1 << i)) != 0)
                        count++;
                }
                maxGroups = Math.max(maxGroups, count);
            }
        }
        System.out.println(maxGroups);
    }
}

